+
+      ros_motion_builder_msgs::ListJointGroups ljg_service;
+      if (list_joints_client_.call(ljg_service))
+      {
+        // Load Group table
+        qDeleteAll(ui_.group_area_->widget()->findChildren<QWidget *>());
