+void RQTMotionBuilder::onPlayClicked()
+{
+  if (!motion_running_)
+  {
+    ros_motion_builder_msgs::RunMotionGoal goal;
+    goal.run_mode = ros_motion_builder_msgs::RunMotionGoal::RUN_MOTION;
+    goal.downshift = ui_.downshift_->value();
+
+    disableBtns();
+    motion_running_ = true;
+    run_motion_client_->sendGoal(goal, boost::bind(&RQTMotionBuilder::runDone, this, _1,
+                                                   _2));  // Add done callback to unlock
+  }
+  else
+  {
+    run_motion_client_->cancelAllGoals();
+    motion_running_ = false;
+  }
